//! Shared Gnosis HTTP stream framing primitives.

use std::io::{Cursor, Read};
use std::sync::mpsc::Receiver;

pub struct SseStream {
    rx: Receiver<Vec<u8>>,
    current: Cursor<Vec<u8>>,
    done: bool,
}

impl SseStream {
    pub fn new(rx: Receiver<Vec<u8>>) -> Self {
        Self {
            rx,
            current: Cursor::new(Vec::new()),
            done: false,
        }
    }
}

impl Read for SseStream {
    fn read(&mut self, buf: &mut [u8]) -> std::io::Result<usize> {
        loop {
            let n = self.current.read(buf)?;
            if n > 0 {
                return Ok(n);
            }
            if self.done {
                return Ok(0);
            }
            match self.rx.recv() {
                Ok(chunk) => {
                    self.current = Cursor::new(chunk);
                }
                Err(_) => {
                    self.done = true;
                    return Ok(0);
                }
            }
        }
    }
}

pub fn sse_event(event: &str, data: &str) -> Vec<u8> {
    format!("event: {event}\ndata: {data}\n\n").into_bytes()
}

pub fn encode_chunked_stream(reader: &mut dyn Read) -> Vec<u8> {
    let mut encoded = Vec::new();
    let mut buf = [0u8; 16 * 1024];
    loop {
        match reader.read(&mut buf) {
            Ok(0) => {
                encoded.extend_from_slice(b"0\r\n\r\n");
                break;
            }
            Ok(n) => {
                encoded.extend_from_slice(format!("{n:x}\r\n").as_bytes());
                encoded.extend_from_slice(&buf[..n]);
                encoded.extend_from_slice(b"\r\n");
            }
            Err(_) => {
                encoded.extend_from_slice(b"0\r\n\r\n");
                break;
            }
        }
    }
    encoded
}

#[cfg(test)]
mod tests {
    use super::{encode_chunked_stream, sse_event, SseStream};
    use std::io::{Cursor, Read};
    use std::sync::mpsc;

    #[test]
    fn sse_event_formats_named_event() {
        assert_eq!(
            sse_event("progress", "{\"stage\":\"queued\"}"),
            b"event: progress\ndata: {\"stage\":\"queued\"}\n\n"
        );
    }

    #[test]
    fn sse_stream_reads_channel_chunks_in_order() {
        let (tx, rx) = mpsc::channel();
        tx.send(sse_event("a", "1")).expect("send a");
        tx.send(sse_event("b", "2")).expect("send b");
        drop(tx);

        let mut stream = SseStream::new(rx);
        let mut out = String::new();
        stream.read_to_string(&mut out).expect("read stream");

        assert_eq!(out, "event: a\ndata: 1\n\nevent: b\ndata: 2\n\n");
    }

    #[test]
    fn encode_chunked_stream_frames_body() {
        let mut reader = Cursor::new(b"hello".to_vec());
        let encoded = encode_chunked_stream(&mut reader);
        assert_eq!(encoded, b"5\r\nhello\r\n0\r\n\r\n");
    }
}
